#include <vector>
#include <algorithm>

long long solve(std::vector<long long> weight) {
    long long max_count = 0;
    int i = 0;
    int n = weight.size();

    while (i < n) {
        long long max_weight = -1;
        int j = i;
        while (j < n) {
            max_weight = std::max(max_weight, static_cast<long long>(weight[j]));
            if (weight[j] < max_weight) {
                max_count += 1;
                i = j + 1;
                break;
            }
            j++;
        }
        if (j == n) {
            i++;
        }
    }

    return max_count;
}
